import{r as d}from"./auth.service.Ci3Tolzm.js";const e=document.getElementById("signup-form"),n=document.getElementById("form-error"),t=document.getElementById("submit-btn");e.addEventListener("submit",async a=>{a.preventDefault(),n.hidden=!0,t.disabled=!0,t.textContent="Creating account…";const r=e.displayName.value.trim(),s=e.email.value.trim(),i=e.password.value;try{await d({displayName:r,email:s,password:i}),window.location.href="/favorites"}catch(o){n.textContent=o.message??"Sign up failed. Please try again.",n.hidden=!1,t.disabled=!1,t.textContent="Sign Up"}});
